import React,{useEffect}from 'react'
import {ReactNavbar} from "react-responsive-animate-navbar";

const Navbar = () => {
    useEffect(()=>{
        var children = document.querySelectorAll(".styles_navLinks__38tON ul li a");
        children.forEach(function(child) {
            // var a = document.getElementById(child);
            child.setAttribute("href", "#aboutme");
            child.on('click', function(event){
                event.preventDefault();
                window.scrollTo(document.querySelector('#aboutme'));
                // $('html, body').animate({
                //     scrollTop: $( $.attr(this, 'href') ).offset().top
                // }, 500);
            });
            // child.href = "#aboutme";
            console.log(child.href);
        },[]);

    });
    return (
        <ReactNavbar
            color="rgb(25,100,50)"
            logo='logo-removebg-preview.png'
            menu={[
                { name: "HOME", to: "/" },
                { name: "ABOUT ME", to: "" },
                { name: "PROJECT", to: "" },
                { name: "CONTACT", to: "" },
            ]}
            social={[
                {
                    name: "Linkedin",
                    url: "https://www.linkedin.com/in/daniel-lee-00991085",
                    icon: ["fab", "linkedin-in"],
                },
                {
                    name: "Github",
                    url: "https://github.com/DMZnoo",
                    icon: ["fab", "github"],
                }
            ]}
        />
    )
};
export default Navbar;
